import flask
from flask import request, jsonify
from flask_oauthlib.authorization_server import AuthorizationServer
from flask_oauthlib.client import OAuthClient

app = flask.Flask(__name__)
app.config["SECRET_KEY"] = "secret"

auth_codes = {}

@app.route("/authorize", methods=["GET"])
def authorize():
    code = request.args.get("code")
    user_id = auth_codes[code]
    return jsonify({"user_id": user_id})

@app.route("/token", methods=["POST"])
def token():
    client_id = request.form.get("client_id")
    client_secret = request.form.get("client_secret")
    code = request.form.get("code")
    user_id = auth_codes[code]
    if client_id == "my-client-id" and client_secret == "my-client-secret":
        return jsonify({"access_token": f"{user_id}-{code}"})
    else:
        return jsonify({"error": "invalid_client"})

@app.route("/revoke", methods=["POST"])
def revoke():
    client_id = request.form.get("client_id")
    client_secret = request.form.get("client_secret")
    access_token = request.form.get("access_token")
    if client_id == "my-client-id" and client_secret == "my-client-secret":
        auth_codes[access_token] = None
        return jsonify({"success": True})
    else:
        return jsonify({"error": "invalid_client"})

if __name__ == "__main__":
    app.run(debug=True)